from dataclasses import dataclass, field
from typing import Optional

@dataclass
class WorkingMemory:
    # Task identification
    goal: str = ""
    current_step: str = ""

    # Accumulated knowledge
    facts: dict[str, str] = field(default_factory=dict)
    decisions: dict[str, str] = field(default_factory=dict)

    # Task tracking
    completed: list[str] = field(default_factory=list)
    pending: list[str] = field(default_factory=list)
    open_questions: list[str] = field(default_factory=list)

    # Agent state
    errors_encountered: list[str] = field(default_factory=list)
    last_action: Optional[str] = None

    def to_prompt_string(self) -> str:
        """Serialise to a compact string for injection into a system prompt."""
        lines = [f"Goal: {self.goal}", f"Current step: {self.current_step}"]
        if self.facts:
            lines.append("Known facts: " + "; ".join(f"{k}={v}" for k, v in self.facts.items()))
        if self.decisions:
            lines.append("Decisions made: " + "; ".join(f"{k}→{v}" for k, v in self.decisions.items()))
        if self.pending:
            lines.append("Pending tasks: " + ", ".join(self.pending))
        if self.completed:
            lines.append(f"Completed: {len(self.completed)} tasks")
        if self.open_questions:
            lines.append("Open questions: " + "; ".join(self.open_questions))
        if self.errors_encountered:
            lines.append("Errors: " + "; ".join(self.errors_encountered[-3:]))  # last 3 only
        return "\n".join(lines)

import anthropic, json
from copy import deepcopy

client = anthropic.Anthropic()

UPDATE_MEMORY_TOOL = {
    "name": "update_memory",
    "description": (
        "Update the working memory with new information learned during the task. "
        "Call this whenever you learn a new fact, make a decision, complete a step, "
        "discover an open question, or change the current step. "
        "Only include fields you want to change — omit the rest."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "goal":             {"type": "string", "description": "Revise the goal if it becomes clearer"},
            "current_step":     {"type": "string", "description": "What the agent is doing right now"},
            "set_fact":         {"type": "object", "description": "Add/update a key-value fact (e.g. {"db_host": "localhost"})"},
            "set_decision":     {"type": "object", "description": "Record a decision (e.g. {"auth_method": "JWT"})"},
            "complete_task":    {"type": "string", "description": "Mark a task as done"},
            "add_pending":      {"type": "string", "description": "Add a new pending task"},
            "add_question":     {"type": "string", "description": "Record an open question"},
            "add_error":        {"type": "string", "description": "Record an error encountered"},
            "last_action":      {"type": "string", "description": "Brief description of the last action taken"},
        },
        "required": [],
    },
}

def apply_memory_update(mem: WorkingMemory, update: dict) -> WorkingMemory:
    """Apply a model-generated update dict to the working memory object."""
    mem = deepcopy(mem)
    if "goal" in update:            mem.goal = update["goal"]
    if "current_step" in update:    mem.current_step = update["current_step"]
    if "set_fact" in update:        mem.facts.update(update["set_fact"])
    if "set_decision" in update:    mem.decisions.update(update["set_decision"])
    if "add_pending" in update:     mem.pending.append(update["add_pending"])
    if "add_question" in update:    mem.open_questions.append(update["add_question"])
    if "add_error" in update:       mem.errors_encountered.append(update["add_error"])
    if "last_action" in update:     mem.last_action = update["last_action"]
    if "complete_task" in update:
        task = update["complete_task"]
        if task in mem.pending:
            mem.pending.remove(task)
        mem.completed.append(task)
    return mem

def build_system_prompt(mem: WorkingMemory) -> str:
    return f"""You are a task-focused AI agent. Your current working memory is:

{mem.to_prompt_string()}

Guidelines:
- Call update_memory whenever you learn something new or complete a step.
- Keep responses focused on the current step.
- If the pending task list is empty and the goal is met, say so clearly.
"""

def agent_step(
    mem: WorkingMemory,
    history: list[dict],
    user_message: str,
    tools: list[dict] | None = None,
) -> tuple[str, WorkingMemory, list[dict]]:
    """Run one agent turn, returning (reply, updated_memory, updated_history)."""
    all_tools = [UPDATE_MEMORY_TOOL] + (tools or [])
    history.append({"role": "user", "content": user_message})

    while True:
        response = client.messages.create(
            model="claude-opus-4-8",
            max_tokens=1024,
            system=build_system_prompt(mem),
            tools=all_tools,
            messages=history,
        )
        # Process tool calls
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                if block.name == "update_memory":
                    mem = apply_memory_update(mem, block.input)
                    result = "Memory updated."
                else:
                    result = f"Unknown tool: {block.name}"
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })

        history.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            reply = next((b.text for b in response.content if b.type == "text"), "")
            return reply, mem, history

        history.append({"role": "user", "content": tool_results})

import json
from dataclasses import asdict
from pathlib import Path

STATE_FILE = Path(".working_memory.json")

def save_memory(mem: WorkingMemory) -> None:
    STATE_FILE.write_text(json.dumps(asdict(mem), indent=2))

def load_memory() -> WorkingMemory:
    if STATE_FILE.exists():
        data = json.loads(STATE_FILE.read_text())
        return WorkingMemory(**data)
    return WorkingMemory()

# Session lifecycle:
mem = load_memory()
history: list[dict] = []
reply, mem, history = agent_step(mem, history, "What's the next step?")
save_memory(mem)
